  async function saveCurrentScene(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();
    if (["saving", "sealing"].includes(sceneSave.status)) return;
    const saveGate = stargateActive;
    setSceneSave({ status: saveGate ? "sealing" : "saving", message: saveGate ? "Gate energy converging into one Return Card" : "Capturing table scene", error: "", card: null });
    try {
      const card = callGame(saveGate ? "createStargateContextCard" : "createSceneSnapshotCard");
      if (!card) throw new Error("No restorable cards are currently on the Tarot table.");
      setSceneSave({ status: saveGate ? "sealing" : "saving", message: saveGate ? "Sealing safe context; joining authority stays transient" : "Persisting scene card", error: "", card });
      const request = fetch(`${tarotDrawApiBase(apiBase)}/api/tarot/cards`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(card)
      });
      const minimumHeroBeat = saveGate ? new Promise((resolve) => window.setTimeout(resolve, 2400)) : Promise.resolve();
      const [response] = await Promise.all([request, minimumHeroBeat]);
      const store = await response.json().catch(() => null);
      if (!response.ok || !store?.cards) throw new Error(store?.error || store?.message || `Scene save failed: ${response.status}`);
      const savedCard = store.cards.find((item) => item.id === card.id) || card;
      const sceneCard = {
        ...card,
        ...savedCard,
        drawScene: card.drawScene,
        sceneSnapshot: tarotDrawSceneSnapshot(savedCard) || card.sceneSnapshot
      };
      onTarotSceneSaved?.({ card: sceneCard, store, sceneSnapshot: sceneCard.sceneSnapshot });
      callGame("spawnSceneCard", {
        card: sceneCard,
        fromStargate: saveGate,
        statusText: saveGate ? `Return Card sealed: ${sceneCard.title}` : `Scene saved: ${sceneCard.title}`
      });
      setSceneSave({
        status: "complete",
        message: saveGate ? `${sceneCard.title} proposed — fresh Pass required` : `${sceneCard.title} saved`,
        error: "",
        card: sceneCard
      });
    } catch (error) {
      if (saveGate) callGame("cancelStargateContextSeal");
      setSceneSave({
        status: "failed",
        message: saveGate ? "Gate Card seal failed" : "Scene save failed",
        error: error?.message || (saveGate ? "Gate Card seal failed" : "Scene save failed"),
        card: null
      });
    }
  }

  async function openStargateMintReview(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();
    const card = savedStargateContextCard;
    if (!card) return;
    setStargateMint({ open: true, status: "reviewing", review: null, result: null, error: "" });
    callGame("setStargateMintStage", "reviewing");
    try {
      const response = await fetch(`${tarotDrawApiBase(apiBase)}/api/tarot/stargate/context-card/review`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ cardId: card.id })
      });
      const payload = await response.json().catch(() => null);
      if (!response.ok || !payload?.review) throw new Error(payload?.message || payload?.error || `Review failed: ${response.status}`);
      setStargateMint({ open: true, status: "ready", review: payload, result: null, error: "" });
      callGame("setStargateMintStage", "proposed_unminted");
      callGame("ingestSpatialTruthEvent", {
        eventId: `proposal-created:${card.id}:${payload.review.reviewDigest}`,
        type: "proposal.created",
        truthStatus: "verified_event",
        observedAt: new Date().toISOString(),
        sourceNode: "hapa-avatar-builder",
        payloadDigest: payload.review.reviewDigest,
        subjectCardId: card.id,
        label: "Candidate revision proposed for human review"
      });
    } catch (error) {
      setStargateMint({ open: true, status: "failed", review: null, result: null, error: error?.message || "Mint review failed" });
      callGame("setStargateMintStage", "failed");
    }
  }

  async function approveStargateMint(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();
    const review = stargateMint.review?.review;
    const card = savedStargateContextCard;
    if (!card || !review?.reviewDigest || stargateMint.status === "minting") return;
    setStargateMint((current) => ({ ...current, status: "minting", error: "" }));
    callGame("setStargateMintStage", "origin_staged");
    try {
      const sessionResponse = await fetch(`${tarotDrawApiBase(apiBase)}/api/local-ui-session`, { method: "POST", headers: { Accept: "application/json" }, credentials: "same-origin" });
      if (!sessionResponse.ok) {
        const sessionFailure = await sessionResponse.json().catch(() => ({}));
        throw new Error(sessionFailure.message || sessionFailure.error || `Local Builder session failed: ${sessionResponse.status}`);
      }
      const response = await fetch(`${tarotDrawApiBase(apiBase)}/api/tarot/stargate/context-card/mint`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "same-origin",
        body: JSON.stringify({
          cardId: card.id,
          reviewDigest: review.reviewDigest,
          approval: { approved: true, decision: "approve", actorId: avatarId || "local-operator", actorType: "human", method: "explicit-ui-control" }
        })
      });
      const payload = await response.json().catch(() => null);
      if (!response.ok || !payload?.state) throw new Error(payload?.message || payload?.error || `Mint failed: ${response.status}`);
      if (payload.origin?.durableAcknowledgement) callGame("setStargateMintStage", "overwind_acknowledged");
      window.setTimeout(() => callGame("setStargateMintStage", payload.state), 520);
      setSceneSave((current) => ({ ...current, card: payload.card || current.card, message: `Return Card · ${String(payload.state).replaceAll("_", " ")}` }));
      setStargateMint((current) => ({ ...current, status: "complete", result: payload, error: "" }));
    } catch (error) {
      setStargateMint((current) => ({ ...current, status: "failed", error: error?.message || "Mint failed" }));
      callGame("setStargateMintStage", "failed");
    }
  }

